const period = 14;
const panicThreshold = 2.0;

const out = [];
for (const item of $input.all()) {
  const rows = item.json;

  if (!Array.isArray(rows) || rows.length < period + 1) {
    throw new Error(`Klines response is too short for RSI(${period}): ${JSON.stringify(rows).slice(0, 300)}`);
  }

  const closes = rows
    .map((r) => Number(Array.isArray(r) ? r[4] : undefined))
    .filter((v) => Number.isFinite(v) && v > 0);

  if (closes.length < period + 1) {
    throw new Error(`Not enough valid close prices for RSI(${period})`);
  }

  let gain = 0;
  let loss = 0;
  const start = closes.length - (period + 1);
  for (let i = start + 1; i < closes.length; i++) {
    const diff = closes[i] - closes[i - 1];
    if (diff >= 0) gain += diff;
    else loss += Math.abs(diff);
  }

  const avgGain = gain / period;
  const avgLoss = loss / period;
  const rsi = avgLoss === 0 ? 100 : (100 - 100 / (1 + avgGain / avgLoss));

  const price = closes[closes.length - 1];
  const previous = closes[closes.length - 2];
  const movePct = previous > 0 ? ((price - previous) / previous) * 100 : 0;

  const isBearish = movePct <= -0.15 || rsi < 35;
  const isBullish = movePct >= 0.15 || rsi > 65;
  const panicScore = movePct <= -panicThreshold ? Math.min(100, Math.abs(movePct) * 20) : 0;

  out.push({
    json: {
      symbol: 'BTCUSDT',
      price: Number(price.toFixed(2)),
      rsi: Number(rsi.toFixed(2)),
      is_bearish: isBearish,
      is_bullish: isBullish,
      panic_score: Number(panicScore.toFixed(2)),
    },
  });
}

return out;
